// Event Approval Handler
add_action('event_approved', function($event_id) {
    $event = get_event_data($event_id);

    // Rephrase content using OpenAI
    $enhanced_content = openai_rephrase($event['description']);

    // Store enhanced content
    update_event_content($event_id, $enhanced_content);

    // Push to Indian Community (GeoDirectory format)
    send_to_geodirectory([
        'title' => $event['title'],
        'content' => $enhanced_content,
        'category' => $event['category']
    ]);
}, 10, 1);
